const movies = items.map(item => item.json);

const question = $('Webhook').first().json.body.question || '';

const lowerQuestion = question.toLowerCase();

function toNumber(value) {
  const number = Number(value);
  return Number.isFinite(number) ? number : 0;
}

let selectedMovies = movies;

if (
  lowerQuestion.includes('highest') ||
  lowerQuestion.includes('top') ||
  lowerQuestion.includes('best imdb') ||
  lowerQuestion.includes('imdb')
) {
  selectedMovies = [...movies]
    .sort((a, b) => toNumber(b.score) - toNumber(a.score))
    .slice(0, 20);
} else if (
  lowerQuestion.includes('roi') ||
  lowerQuestion.includes('profit') ||
  lowerQuestion.includes('genre')
) {
  selectedMovies = movies
    .filter(movie => toNumber(movie.budget) > 0 && toNumber(movie.gross) > 0)
    .sort((a, b) => toNumber(b.roi) - toNumber(a.roi))
    .slice(0, 50);
} else {
  const matchedMovie = movies.find(movie => {
    const movieName = String(movie.name || '').toLowerCase();
    return movieName && lowerQuestion.includes(movieName);
  });

  if (matchedMovie) {
    const sameGenreMovies = movies
      .filter(movie =>
        movie.genre === matchedMovie.genre &&
        movie.name !== matchedMovie.name
      )
      .sort((a, b) => toNumber(b.roi) - toNumber(a.roi))
      .slice(0, 15);

    selectedMovies = [matchedMovie, ...sameGenreMovies];
  } else {
    selectedMovies = movies.slice(0, 50);
  }
}

let movieText = '';

for (const movie of selectedMovies) {
  movieText += `
Movie: ${movie.name}
Genre: ${movie.genre}
Budget: ${movie.budget}
Gross: ${movie.gross}
IMDb Score: ${movie.score}
Votes: ${movie.votes}
Runtime: ${movie.runtime}
ROI: ${movie.roi}
`;
}

const prompt = `
You are a professional movie analyst.

Answer the user's question using ONLY the movie dataset below.

User Question:
${question}

Movie Dataset:
${movieText}

Rules:
1. Give a short and clear answer.
2. Use numbers from the dataset.
3. If asked for highest IMDb score, choose the movie with the highest IMDb Score.
4. If explaining success or failure, discuss budget, gross, ROI, IMDb score, votes, genre, and runtime.
5. Compare with similar movies if available.
6. Do not guess outside the dataset.
`;

return [
  {
    json: {
      prompt
    }
  }
];
